INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Condutor','Gestão de Qualidade','Lidera iniciativas de segurança do paciente e promove o uso rigoroso dos EPIs.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','8628a9c3-5b3b-414b-8ebc-fdd394b5d7e0'::uuid),
	 ('Condutor','Suporte e desenvolvimento','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI)?',2,'Garantir feedback mensal para 100% da equipe operacional. Identificar lacunas de competência no atendimento de urgência. ',true,'2026-06-30 16:29:11.896276','Liderado > Lider','b1b5c5c9-b635-4224-baaa-f55cd25973a6'::uuid),
	 ('Enfermeiro','Suporte e desenvolvimento','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',true,'2026-06-30 16:30:14.65642','Liderado > Lider','ce58ac27-8629-4419-98b1-375c54b54881'::uuid),
	 ('Enfermeiro','Liderança gestão','As decisões do líder são tomadas com transparência critérios técnicos e considerando o impacto na equipe?',2,'No contexto do SAMU, tomar decisões técnicas (como seguir à risca os protocolos de triagem ou priorização de viaturas) e explicar os motivos de forma transparente para a equipe evita boatos na base e fortalece a confiança no comando.',true,'2026-06-30 13:32:48.121518','Liderado > Lider','f75c408b-1f16-4c94-9f4a-11b3efa6925b'::uuid),
	 ('Condutor','EIXO SOFT SKILLS','Trata pacientes, familiares e equipe com respeito, sigilo e ética, respeitando a dignidade humana Ética e humanização.',1,'Esse é um pilar fundamental para qualquer profissional da área da saúde ou do cuidado humano. A prática baseada no respeito, sigilo, ética e dignidade garante um ambiente seguro e acolhedor para todos os envolvidos',true,'2026-06-30 11:02:57.776166','autoavaliacao','3323ee62-b181-4fa7-96bf-e2c732b3af8f'::uuid),
	 ('Condutor','Comportamental','Mantém controle emocional em cenários de alta tensão, múltiplas vítimas, violência ou óbito',1,'Controle emocional',false,'2026-06-10 10:02:38.389329','autoavaliacao','efbd3ae9-8e67-4428-8860-cf58b4ae8b3f'::uuid),
	 ('Condutor','Técnico-Operacional','Manuseia corretamente a maca, cadeira de rodas, prancha longa e colar cervical',1,'Manuseio de equipamentos',false,'2026-06-10 10:02:38.389329','autoavaliacao','ea461535-536b-4de0-a429-54fd208b6cfc'::uuid),
	 ('Técnico de Enfermagem','EIXO TÉCNICO','Manuseia corretamente: oxímetro, monitor cardíaco, respirador, glicosímetro e demais equipamentos da USB/USA Manuseio de equipamentos?',1,'O manuseio adequado foca na segurança do paciente, estabilização dos sinais vitais e transporte seguro',true,'2026-06-30 13:19:15.285353','autoavaliacao','ccc493c8-bab0-4999-b1a6-d4a421058e81'::uuid),
	 ('Técnico de Enfermagem','Gestão e Liderança','Medeia conflitos interpessoais de forma profissional, imparcial e orientada para a solução.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','f5187bb2-f3ea-47a8-9573-cfb52839b134'::uuid),
	 ('Condutor','EIXO TÉCNICO','Manuseia corretamente a maca, cadeira de rodas, prancha longa e colar cervical (Manuseio de equipamentos)',1,'Manuseio correto de equipamentos de imobilização e transporte exige treinamento, comunicação constante e movimentação em bloco.',true,'2026-06-30 11:16:11.659225','autoavaliacao','891047b8-1247-42a5-9749-802f3f3ea185'::uuid);
