	 ('Condutor','Processo e Qualidade','Preenche corretamente o registro de saída e chegada da viatura, tempo de deslocamento e ocorrências relevantes',1,'Completude dos registros',false,'2026-06-10 10:02:38.389329','autoavaliacao','e3f334f8-9cd8-4074-9c7d-7a1b3e7c01e1'::uuid);
