	 ('Condutor','Gestão e Liderança','Toma decisões operacionais de forma ágil e embasada, consultando a equipe quando necessário.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','be0465e6-bac1-4ffd-80a8-b715c4003826'::uuid),
