	 ('BP-TEAM','Gerenciamento de Tarefas','Os procedimentos são executados com técnica correta, sem erros ou omissões significativas',1,'',false,'2026-06-10 10:02:38.389329','autoavaliacao','2376d7f7-4aaf-4bda-aec9-28c9f371eb7e'::uuid),
	 ('BP-TEAM','Trabalho em Equipe','Todos os membros compartilham o mesmo modelo mental do quadro clínico e plano de ação',1,'',false,'2026-06-10 10:02:38.389329','autoavaliacao','7467c67c-83f7-46ec-8cd7-dcfcb4e5eb0d'::uuid),
	 ('Médico','Suporte e desenvolvimento','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI)?',2,'Garantir feedback mensal para 100% da equipe operacional. Identificar lacunas de competência no atendimento de urgência. ',true,'2026-06-30 16:29:11.896276','Liderado > Lider','f4ba4c4e-83ff-4dd1-88fb-aa48160dd07d'::uuid),
	 ('Enfermeiro','Gestão e Liderança','Medeia conflitos interpessoais de forma profissional, imparcial e orientada para a solução.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','3d2377b4-c08f-4840-8b65-db5f61cc5d43'::uuid),
	 ('Enfermeiro','Gestão de Qualidade','Lidera iniciativas de segurança do paciente e promove o uso rigoroso dos EPIs.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','5a16c0df-6518-47e0-ab24-a14e1c26fbcb'::uuid),
	 ('Médico','Suporte e desenvolvimento','O líder incentiva a desenvolvimento profissional da equipe, apoiando capacitações e o crescimento na carreira?',2,'Incentiva a equipe a fazer cursos de especialização (como suporte avançado de vida) e progredir na carreira de urgência e emergência.',true,'2026-06-30 16:29:41.288345','Liderado > Lider','58af1800-957b-4aa6-8254-ddc8bcc045e5'::uuid),
	 ('Médico','Liderança gestão','O(s) líder coordena a equipe de forma organizada, distribuindo tarefas com clarezas e justiça?',2,'isso é fundamental para garantir que as escalas de plantão, a divisão de responsabilidades pela checagem das viaturas (insumos/medicamentos) e a limpeza da base sejam feitas de forma equilibrada, sem sobrecarregar nenhum profissional.',true,'2026-06-30 13:32:04.689644','Liderado > Lider','8b17ba86-3b61-40f2-ab38-bb75ea2c39c5'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Condutor','Técnico-Operacional','Mantém a ambulância limpa, organizada e em condições sanitárias adequadas após cada atendimento',1,'Higienização ambulância',false,'2026-06-10 10:02:38.389329','autoavaliacao','ca7f02b8-c5ec-4ed5-af91-a29f95c6e3e4'::uuid),
	 ('Médico','Relacionamento','Cria um ambiente de trabalho seguro e colaborativo, onde a equipe se sente à vontade para reportar erros sem receio de represálias.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','39a60fd2-37ac-40ef-9cd0-e3466d783161'::uuid),
	 ('Técnico de Enfermagem','Desenvolvimento da Equipe','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','bc9c680e-634b-49a6-8c78-ffd55c6a467f'::uuid),
	 ('Técnico de Enfermagem','Comportamental','Usa corretamente todos os EPIs e adota medidas de segurança para si, paciente e equipe em toda cena',1,'Segurança / EPIs',false,'2026-06-10 10:02:38.389329','autoavaliacao','ccca67ff-9c0f-46eb-94c2-0d3a1429fe1d'::uuid),
	 ('Condutor','Técnico-Operacional','Auxilia a equipe nos procedimentos de Suporte Básico de Vida (SBV): RCP, imobilização, oxigenoterapia básica',1,'Competência SBV',false,'2026-06-10 10:02:38.389329','autoavaliacao','75f020e3-e9ff-4122-9ba0-f4d2a31c8a65'::uuid),
	 ('Técnico de Enfermagem','Liderança','Usa comunicação em loop fechado (call-out, check-back) para garantir compreensão das ordens na cena',1,'Comunicação em loop (NTS)',false,'2026-06-10 10:02:38.389329','autoavaliacao','300165eb-b5bd-4aca-91ba-a8de70eae96b'::uuid),
	 ('Técnico de Enfermagem','Técnico-Clínico','Conhece e segue os protocolos clínicos do SAMU-192 (sepse, IAM, AVC, trauma, PCR, intoxicação)',1,'Adesão a protocolos',false,'2026-06-10 10:02:38.389329','autoavaliacao','0bf2c05b-f1eb-4a02-b0ef-320de78890bd'::uuid),
	 ('Técnico de Enfermagem','Técnico-Clínico','Executa técnica correta de movimentação e transporte de pacientes críticos sem agravar lesões',1,'Técnica de transporte',false,'2026-06-10 10:02:38.389329','autoavaliacao','af16d318-7300-433f-a1ee-031e1383e03c'::uuid),
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','Mantém foco e equilíbrio emocional em situações de alta pressão (PCR, múltiplas vítimas, violência) Controle emocional?',1,'Manter a calma em situações de alta pressão, como PCR ou múltiplas vítimas, exige treinamento e técnicas rápidas de regulação psicofisiológica.',true,'2026-06-30 13:21:21.239054','autoavaliacao','3324e363-d79c-4a7b-80c0-566c4ba62707'::uuid),
	 ('Condutor','Liderança gestão','O líder demonstra domínio técnico e conhecimento das rotinas suficientes para orientar a equipe com segurança?',2,'o líder precisa dominar as rotinas operacionais (fluxos de regulação, protocolos contratuais) e os protocolos assistenciais de ponta (como o PHTLS, ACLS e diretrizes de trauma/cardio) para que a equipe sinta total segurança ao seguir suas ordens em situações críticas.',true,'2026-06-30 13:33:32.9942','Liderado > Lider','274ab4f7-44a1-486e-8c66-3c6e996267bb'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Médico','Suporte e desenvolvimento','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',true,'2026-06-30 16:30:14.65642','Liderado > Lider','fcf9513d-f01f-47d0-b394-c0f82b9cf138'::uuid),
	 ('Técnico de Enfermagem','Gestão e Liderança','Distribui escalas, atribuições e cargas de trabalho de forma justa e equilibrada entre os membros.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','131c0b98-9f09-46fe-a8d7-d9f8e23a303b'::uuid),
	 ('Condutor','Comunicação e disponibilidade','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos?',2,'A líder monitora ativamente os atendimentos diários para garantir a qualidade assistencial. Realiza o planejamento e ajuste da tripulação (escala) de forma justa e eficiente. Executa o processo de acolhimento e treinamento prático de novos colaboradores (onboarding).',true,'2026-06-30 13:34:48.761055','Liderado > Lider','188bc8d0-5249-446a-855e-e5fbe15301b1'::uuid),
	 ('Médico','Liderança','Utiliza comunicação em loop com a equipe, confirmando ordens e mantendo registro verbal das condutas.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','f25e05a0-d6e2-4f14-bfe7-832732c9f491'::uuid),
	 ('Técnico de Enfermagem','Comportamental','Age com ética e discrição no exercício da função.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','c15464a7-39dc-4998-9c1b-07e64904833f'::uuid),
	 ('Enfermeiro','Comportamental','Usa corretamente todos os EPIs e adota medidas de segurança para si, paciente e equipe em toda cena',1,'Segurança / EPIs',false,'2026-06-11 15:06:08.472675','autoavaliacao','bfb6a314-d997-458b-8a79-26ec7fe6e895'::uuid),
	 ('Médico','Trabalho em Equipe','Utilizo comunicação em loop fechado (call-out e check-back) de forma consistente nos atendimentos.',1,'',false,'2026-06-11 17:47:31.017876','autoavaliacao','e7971d12-d19d-4ba5-a69b-29b73a72f459'::uuid),
	 ('BP-TEAM','Habilidades Não Técnicas (NTS)','A equipe mantém desempenho técnico adequado mesmo em cenários de alta carga emocional',1,'',false,'2026-06-10 10:02:38.389329','autoavaliacao','116343e2-5595-4c2c-88b9-7825c8123565'::uuid),
	 ('BP-TEAM','Liderança','O líder toma decisões de forma assertiva, sem hesitação excessiva, mesmo sob pressão extrema',1,'',false,'2026-06-10 10:02:38.389329','autoavaliacao','f308c161-e82f-4708-aed3-442618414ec1'::uuid),
	 ('Técnico de Enfermagem','Desenvolvimento da Equipe','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI).',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','1902ec7e-ffcb-4edc-aee4-be8ada448e4a'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Condutor','Metas e desenvolvimento - Transversais','Busco ativamente meu desenvolvimento profissional por meio de capacitações, leituras, treinamentos inlocco, e trocas com equipe.',1,'Essa é uma excelente estratégia de carreira. Combinar capacitações, leituras e trocas com a equipe garante um desenvolvimento contínuo.',true,'2026-06-30 11:19:49.690665','autoavaliacao','8aac5dcf-82b7-4d0f-bbd0-0f1567eb748c'::uuid),
	 ('Técnico de Enfermagem','Técnico-Clínico','Reconhece limitações e aciona o médico regulador/intervencionista nos momentos adequados',1,'Escalada de cuidados',false,'2026-06-10 10:02:38.389329','autoavaliacao','205d4454-6153-4848-9a21-94a604d66e32'::uuid),
	 ('Médico','Liderança gestão','As decisões do líder são tomadas com transparência critérios técnicos e considerando o impacto na equipe?',2,'No contexto do SAMU, tomar decisões técnicas (como seguir à risca os protocolos de triagem ou priorização de viaturas) e explicar os motivos de forma transparente para a equipe evita boatos na base e fortalece a confiança no comando.',true,'2026-06-30 13:32:48.121518','Liderado > Lider','fd9aaf6a-2b90-422d-baa5-56d670e5635b'::uuid),
	 ('Condutor','Comportamental','Trata pacientes, familiares e equipe com respeito, sigilo e ética, respeitando a dignidade humana',1,'Ética e humanização',false,'2026-06-10 10:02:38.389329','autoavaliacao','c90da991-9b09-4ed5-bd04-1c406d5c8559'::uuid),
	 ('Condutor','Comportamental','Utiliza corretamente todos os EPIs obrigatórios (luvas, máscara, avental) em todos os atendimentos',1,'Uso de EPIs',false,'2026-06-10 10:02:38.389329','autoavaliacao','cb9367a1-e6cf-4035-8f04-da6e5c939a8e'::uuid),
	 ('Técnico de Enfermagem','Técnico-Clínico','Realiza avaliação clínica completa (SAMPLA, ABCDE, Glasgow, FAST) e formula diagnósticos de enfermagem precisos',1,'Avaliação SAMPLA/ABCDE',false,'2026-06-10 10:02:38.389329','autoavaliacao','3305315e-0169-4065-8816-e35c5315b036'::uuid),
	 ('Técnico de Enfermagem','Técnico-Clínico','Realiza imobilização adequada de vítimas de trauma (colar cervical, prancha, talas) conforme protocolo PHTLS',1,'Imobilização PHTLS',false,'2026-06-10 10:02:38.389329','autoavaliacao','08a2bf96-bf83-43aa-9217-b58ad1d054d3'::uuid),
	 ('Enfermeiro','Gestão e Liderança','Toma decisões operacionais de forma ágil e embasada, consultando a equipe quando necessário.',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','1419d110-703f-4f5f-bdf0-0c5a105ded94'::uuid),
	 ('Médico','Liderança gestão','O líder demonstra domínio técnico e conhecimento das rotinas suficientes para orientar a equipe com segurança?',2,'o líder precisa dominar as rotinas operacionais (fluxos de regulação, protocolos contratuais) e os protocolos assistenciais de ponta (como o PHTLS, ACLS e diretrizes de trauma/cardio) para que a equipe sinta total segurança ao seguir suas ordens em situações críticas.',true,'2026-06-30 13:33:32.9942','Liderado > Lider','5cb3cf4d-e7eb-4c49-bdaa-2a52f3629668'::uuid),
	 ('Condutor','Comportamental','Avalia a segurança da cena antes de se aproximar e comunica os riscos à equipe (tráfego, violência, substâncias).',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','935ad302-76d4-4aa5-a76c-9c54fc5df13e'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Condutor','Técnico Operacional','Conhece e utiliza corretamente rotas de acesso, vias alternativas e GPS para otimização do tempo-resposta.',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','86025267-fcb5-4b5d-8112-f22d6a99b869'::uuid),
	 ('Condutor','Técnico Operacional','Mantém a ambulância limpa, organizada e em condições sanitárias adequadas após cada atendimento.',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','fd38757e-8cd5-4dd9-a6fd-33b6410bd393'::uuid),
	 ('Enfermeiro','Comportamental','Contribui para as metas operacionais: tempo-resposta ≤ 15min, tempo de cena ≤ 20min e ROSC em PCR.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','2dc1ae3d-a8a5-499c-b19e-12369760ccd4'::uuid),
	 ('Enfermeiro','Liderança','Encontra soluções criativas e adequadas diante de cenários complexos ou com recursos limitados.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','885cd73e-1fec-4210-8a4c-08afa3402999'::uuid),
	 ('Enfermeiro','Técnico / Clínico','Administra medicamentos de urgência com segurança, verificando prescrição, dose, via e tempo de administração.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','0093a411-c232-43f0-ba96-585bbccdfd69'::uuid),
	 ('Enfermeiro','Técnico / Clínico','Executa com precisão procedimentos de SAV: acesso venoso difícil, intubação orotraqueal, RCP avançada e desfibrilação.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','3375fe0b-93e5-4d57-b4e6-f84e7f7555f5'::uuid),
	 ('Médico','Comportamental','Documenta o atendimento médico de forma completa: hipótese diagnóstica, condutas, medicamentos e encaminhamento.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','414e57fc-f8ff-4165-b396-0b2f2f635a6b'::uuid),
	 ('Médico','Técnico / Clínico','Aplica o protocolo de IAM (ACLS): ECG, trombolítico, ativação hemodinâmica, cumpre o tempo porta-balão ≤ 90min.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','23f018e0-2b97-490c-a556-df6ab66e952a'::uuid),
	 ('Médico','Técnico / Clínico','Aplica o protocolo de AVC (FAST/NIHSS) e aciona a linha de cuidado cerebrovascular conforme POP.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','560f8c6d-2f8a-4162-a6ec-039849043bcc'::uuid),
	 ('Médico','Técnico / Clínico','Comunica-se eficientemente com o médico regulador da CRUR-BF: informações precisas, decisão conjunta e tempo de regulação.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','bcd82744-506d-4c6f-861e-93c59cb6389c'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
