	 ('Técnico de Enfermagem','Comportamental','Demonstra responsabilidade e comprometimento com suas atividades.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','6a7ef340-21f9-4d23-a290-9881f37bb5a7'::uuid),
	 ('Técnico de Enfermagem','Processo e Qualidade','Executa o transporte seguro de pacientes críticos, sem agravar lesões existentes.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','e7b09311-5a12-4fa2-ae1e-99b240e5c5ed'::uuid),
	 ('Técnico de Enfermagem','Técnico / Clínico','Executa corretamente compressões torácicas, ventilação (bolsa-valva-máscara) e desfibrilação com DEA.',2,NULL,false,'2026-06-16 13:09:10.993845','Lider > Liderado','a3d4a623-861d-469e-9d42-16b13ab12e60'::uuid),
	 ('Técnico de Enfermagem','Técnico / Clínico','Realiza punção venosa periférica e administra medicamentos conforme prescrição do enfermeiro/médico.',2,NULL,false,'2026-06-16 13:09:10.993845','Lider > Liderado','8b87b6d7-54a7-499f-b9fa-66523c48e0e6'::uuid),
	 ('Enfermeiro','Comportamental','Participa ativamente do trabalho em equipe, recebe e transmite informações de forma padronizada (SBAR)',1,'Comunicação SBAR / trabalho em equipe',false,'2026-06-11 15:06:08.472675','autoavaliacao','3b936ddf-9b35-4dba-9ce7-74f918c523e7'::uuid),
	 ('Enfermeiro','Processo e Qualidade','Registra o Processo de Enfermagem no SAMU de forma completa, legível e juridicamente válida',1,'Completude do Registro PE/SAMU (IVC ≥0,80)',false,'2026-06-11 15:06:08.472675','autoavaliacao','807bcc65-7dbf-42d7-ada8-83cc5ffb6f53'::uuid),
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','Identifica e comunica sinais de gravidade imediata ao Enfermeiro/médico com precisão, agilidade Triagem e comunicação?',1,'Identificar e comunicar sinais de alerta com precisão e agilidade é vital na triagem. Durante o Acolhimento com Classificação de Risco',true,'2026-06-30 13:22:25.766942','autoavaliacao','4559065d-f39b-47a0-bbdf-706c716ebde7'::uuid),
	 ('Condutor','Comportamental','Integra-se ativamente à equipe, antecipando necessidades, cooperando na cena e comunicando informações relevantes.',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','b6e86485-b084-47ef-a04c-4252fb0209d0'::uuid),
	 ('Condutor','Comportamental','Trata pacientes, familiares e equipe com respeito, sigilo e ética, preservando a dignidade humana.',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','2e3288d5-4894-427e-a245-9f48e919483b'::uuid);
