	 ('Condutor','Processo e Qualidade','Preenche corretamente o registro de saída e chegada da viatura, tempo de deslocamento e ocorrências relevantes.',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','d97ffaed-63df-4c09-a0dc-70eb33dcd8dd'::uuid),
