	 ('Enfermeiro','Comportamental','Demonstra responsabilidade e comprometimento, sendo referência de conduta para a equipe.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','a697f4cf-3c3f-462c-9853-1907d188320e'::uuid),
	 ('Enfermeiro','Comportamental','Mantém comunicação clara, respeitosa e empática com pacientes, familiares e equipe.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','023b708a-5b42-471d-b8d8-77fb2a0b234f'::uuid),
	 ('Enfermeiro','Comportamental','Mantém postura ética e discrição absoluta em todas as situações de atendimento.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','40765604-346a-405f-a58e-b48eaa72bcbd'::uuid),
	 ('Enfermeiro','Liderança','Lidera pelo exemplo no uso correto de EPIs e na aplicação de precauções de segurança em toda a cena.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','bf72d397-3fd6-4e99-9af3-77157ad61cd8'::uuid),
	 ('Enfermeiro','Liderança','Mantém e compartilha a consciência situacional com toda a equipe (briefing e atualização contínua).',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','fc2a0914-ebf7-49e9-ac8e-6a70b81f91f9'::uuid),
	 ('Enfermeiro','Técnico / Clínico','Realiza avaliação clínica completa (SAMPLA, ABCDE, Glasgow, FAST) e formula diagnósticos de enfermagem precisos.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','52a6d28c-a25b-47b8-836a-6c97cfd07c3c'::uuid),
	 ('Enfermeiro','Liderança','Organiza as tarefas sequencialmente, priorizando intervenções conforme gravidade e tempo-crítico.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','8bfcd30b-4a9f-4061-8236-36b576197b82'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Enfermeiro','Técnico / Clínico','Toma decisões clínicas rápidas e assertivas em cenários de IAM, AVC, trauma grave, sepse e PCR.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','7a78a078-6487-4770-9905-cd92784eed4f'::uuid),
	 ('Enfermeiro','Técnico / Clínico','Reconhece limitações técnicas e aciona o médico regulador/intervencionista nos momentos adequados.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','964d304f-5057-4127-b5d5-e1465a3d39c8'::uuid),
	 ('Enfermeiro','Técnico / Clínico','Supervisiona o técnico de enfermagem e o condutor, orientando procedimentos e prevenindo erros.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','20b2a020-771a-4954-a9d2-58800ee3c0ef'::uuid),
	 ('Médico','Comportamental','Mantém postura ética e discrição absoluta em todas as situações de atendimento.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','d1e4cf30-41a9-4d5e-8f2d-117412347d88'::uuid),
	 ('Médico','Liderança','Mantém consciência situacional ampla (cena, paciente, equipe, recursos, tempo) e adapta o plano de cuidado.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','4858fd26-420b-4269-9345-f76f3bb42fda'::uuid),
	 ('Médico','Liderança','Toma decisões rápidas e assertivas sob pressão extrema, com base em evidências e priorização correta.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','c47281a2-c811-40d1-b034-2b521fa1040c'::uuid),
	 ('Médico','Liderança','Gerencia simultaneamente múltiplas tarefas críticas: paciente, equipe, comunicação com regulação e documentação.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','e60f4232-5dde-481a-9160-55d0cd11cfe5'::uuid),
	 ('Médico','Liderança','Lidera a equipe USA com autoridade, clareza e empatia: define papéis, distribui tarefas e mantém a segurança.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','7f8ea5d8-22b8-4bec-9c7d-afb6809fa165'::uuid),
	 ('Médico','Técnico / Clínico','Prescreve, verifica e supervisiona a administração de medicamentos de urgência com segurança e precisão.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','45852226-6892-4a3f-ab5d-3b30bd8aa023'::uuid),
	 ('Médico','Técnico / Clínico','Realiza avaliação clínica completa e rápida, formulando diagnóstico sindromático correto no pré-hospitalar.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','aa5900b7-6413-4ed1-9c1b-f22a5112b385'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Técnico de Enfermagem','Comportamental','Mantém controle emocional e profissionalismo em situações de alta pressão.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','6e5e2816-3739-478a-a557-0e5530ea92a8'::uuid),
	 ('Técnico de Enfermagem','Comportamental','Mantém relacionamento respeitoso com pacientes, familiares e colegas de trabalho.',2,NULL,false,'2026-06-16 13:09:10.993845','Lider > Liderado','fb3c0a92-562c-472c-83b1-ca77ca3abd74'::uuid),
	 ('Técnico de Enfermagem','Liderança Situacional','Mantém atenção à situação da ocorrência, acompanhando o estado do paciente, os equipamentos e as condições do ambiente.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','4bcff6d4-d9d0-4d3e-aaa1-b00d43441f4a'::uuid),
	 ('Técnico de Enfermagem','Liderança Situacional','Participa ativamente do trabalho em equipe, comunicando e recebendo informações de forma clara e organizada.',2,NULL,false,'2026-06-16 13:09:10.993845','Lider > Liderado','6faf634c-aeab-4d0b-a854-0cdfeff16971'::uuid),
	 ('Técnico de Enfermagem','Processo e Qualidade','Preenche corretamente os registros de atendimento com informações precisas e no tempo adequado.',2,NULL,false,'2026-06-16 13:09:10.993845','Lider > Liderado','d96bdd93-a028-458f-8d93-d99142bd3a5d'::uuid),
	 ('Técnico de Enfermagem','Técnico / Clínico','Conhece e segue os protocolos clínicos do SAMU-192 (sepse, IAM, AVC, trauma, PCR, intoxicação).',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','529bfc85-0bb9-44d9-af7d-3bcf0e353a6e'::uuid),
	 ('Técnico de Enfermagem','Técnico / Clínico','Realiza imobilização adequada de vítimas de trauma (colar cervical, prancha, talas) conforme protocolo PHTLS.',2,NULL,false,'2026-06-16 13:09:10.993845','Lider > Liderado','ad8177e3-6e38-40d6-9e22-e77e6231ebf9'::uuid),
	 ('Técnico de Enfermagem','Técnico / Clínico','Manuseia corretamente os equipamentos da USB/USA: oxímetro, monitor cardíaco, respirador e glicosímetro.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','d4369133-aa66-4982-8fdc-c82868ee4e39'::uuid),
	 ('Condutor','Metas e desenvolvimento - Transversais','Tenho clareza sobre minhas motivações profissionais que nos mantém engajado no trabalho no SAMU 192',1,'Compreender as próprias motivações no SAMU 192 é o que fortalece a resiliência diária e o vínculo com a missão de salvar vidas.',true,'2026-06-30 11:20:41.748116','autoavaliacao','bbefebdb-2f27-4bff-8760-76c1f3fa47ba'::uuid),
	 ('Médico','Desenvolvimento da Equipe','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI).',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','062754aa-d86f-494a-98ad-a4c1a847fbd5'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Enfermeiro','Desenvolvimento da Equipe','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI).',2,'',false,'2026-06-16 19:12:56.829486','Liderado > Lider','e72109ae-b7d5-491e-afe3-1f600314eb0e'::uuid),
	 ('Condutor','EIXO SOFT SKILLS','Contribui para o cumprimento do tempo-resposta ≤15 minutos da central ao local (Portaria MS 2.048/2002)',1,'O cumprimento do tempo-resposta de ≤ 15 minutos da Central ao local exige a descentralização das bases do SAMU, dimensionamento correto da frota, otimização das rotas de tráfego e equipes capacitadas sob rigorosa regulação médica. Em locais distantes onde o tempo terrestre supere essa marca, recomenda-se o acionamento de resgate aeromédico',true,'2026-06-30 11:11:21.321903','autoavaliacao','40ca12fd-81be-4272-8c2d-d17922d1e740'::uuid),
	 ('Condutor','EIXO TÉCNICO','Realizo autoavaliação crítica da minha prática assistências, identificando lacunas e buscando corrigi-las.',1,'Essa é uma prática fundamental e altamente recomendada na área da saúde. Realizar a autoavaliação crítica da própria prática assistencial, identificar lacunas e buscar o aprimoramento contínuo garante a segurança do paciente e a excelência no cuidado.',true,'2026-06-30 11:19:18.872887','autoavaliacao','80aaba6a-988e-4937-80a4-44d6e78ae517'::uuid),
	 ('Enfermeiro','Liderança gestão','O líder demonstra domínio técnico e conhecimento das rotinas suficientes para orientar a equipe com segurança?',2,'o líder precisa dominar as rotinas operacionais (fluxos de regulação, protocolos contratuais) e os protocolos assistenciais de ponta (como o PHTLS, ACLS e diretrizes de trauma/cardio) para que a equipe sinta total segurança ao seguir suas ordens em situações críticas.',true,'2026-06-30 13:33:32.9942','Liderado > Lider','2d075c7a-3857-46ae-a5b3-e897993981bf'::uuid),
	 ('Condutor','Liderança gestão','O(s) líder coordena a equipe de forma organizada, distribuindo tarefas com clarezas e justiça?',2,'isso é fundamental para garantir que as escalas de plantão, a divisão de responsabilidades pela checagem das viaturas (insumos/medicamentos) e a limpeza da base sejam feitas de forma equilibrada, sem sobrecarregar nenhum profissional.',true,'2026-06-30 13:32:04.689644','Liderado > Lider','a17954ab-1eae-460e-8c5d-7b3c2e17d285'::uuid),
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','Mantém consciência situacional: monitora o estado do paciente, equipamentos e ambiente simultaneamente Consciência situacional NTS?',1,'A manutenção da consciência situacional (Habilidade Não Técnica - HNT) evita a fixação de foco e a sobrecarga de trabalho. Monitorar paciente, equipamentos e ambiente simultaneamente, além de identificar sinais precoces de deterioração clínica e comunicar efetivamente, previne erros e é essencial para a segurança no cuidado.',true,'2026-06-30 13:21:58.727001','autoavaliacao','e0f1a7bd-a731-458f-9ecc-c9b50c12ffae'::uuid),
	 ('Médico','Comunicação e disponibilidade','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos?',2,'A líder monitora ativamente os atendimentos diários para garantir a qualidade assistencial. Realiza o planejamento e ajuste da tripulação (escala) de forma justa e eficiente. Executa o processo de acolhimento e treinamento prático de novos colaboradores (onboarding).',true,'2026-06-30 13:34:48.761055','Liderado > Lider','73d3d65b-e66e-417f-9777-d0ea5de5225d'::uuid),
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI)?',2,'Garantir feedback mensal para 100% da equipe operacional. Identificar lacunas de competência no atendimento de urgência. ',true,'2026-06-30 16:29:11.896276','Liderado > Lider','de7dd6ca-9bb5-49c3-a430-efbd288698ab'::uuid),
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','O líder incentiva a desenvolvimento profissional da equipe, apoiando capacitações e o crescimento na carreira?',2,'Incentiva a equipe a fazer cursos de especialização (como suporte avançado de vida) e progredir na carreira de urgência e emergência.',true,'2026-06-30 16:29:41.288345','Liderado > Lider','10d3ebf1-c609-481f-81d6-de7688f4951f'::uuid),
	 ('Técnico de Enfermagem','Liderança gestão','O(s) líder coordena a equipe de forma organizada, distribuindo tarefas com clarezas e justiça?',2,'isso é fundamental para garantir que as escalas de plantão, a divisão de responsabilidades pela checagem das viaturas (insumos/medicamentos) e a limpeza da base sejam feitas de forma equilibrada, sem sobrecarregar nenhum profissional.',true,'2026-06-30 13:32:04.689644','Liderado > Lider','579bd70c-92d5-4c0b-818d-fb446582ddcd'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',true,'2026-06-30 16:30:14.65642','Liderado > Lider','faa38a55-bf95-40aa-88e9-293e0d6a7cae'::uuid),
	 ('Condutor','Comunicação e disponibilidade','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',true,'2026-06-30 13:36:05.370723','Liderado > Lider','28618483-f0d5-4b13-bc26-63afecc95b86'::uuid),
	 ('Enfermeiro','Comunicação e disponibilidade','O líder está disponível e acessível quando a equipe precisa de suporte, orientação ou decisão rápida?',2,'onde os segundos salvam vidas e as crises operacionais acontecem a qualquer hora do dia ou da noite, ter um líder acessível para resolver impasses de frota, problemas na regulação ou conflitos na base é fundamental.',true,'2026-06-30 16:27:54.328435','Liderado > Lider','9e2f3240-e7f2-4eb1-bea2-9f588882b489'::uuid),
	 ('Condutor','Técnico Operacional','Realiza o checklist completo da viatura no início do plantão (combustível, pneus, equipamentos, kit de emergência).',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','c4f653b7-4845-433f-a6f8-85bf8a5e38ea'::uuid),
	 ('Enfermeiro','Comportamental','Registra o Processo de Enfermagem de forma completa, legível e juridicamente válida.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','485096a1-0ff7-428d-b3bf-5a0c92601020'::uuid),
	 ('Técnico de Enfermagem','Liderança Situacional','Mantém foco e equilíbrio emocional em situações de pressão, agindo com profissionalismo e respeito.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','0dc78c8d-8f97-4442-8071-3f19f503ef91'::uuid),
	 ('Técnico de Enfermagem','Liderança gestão','As decisões do líder são tomadas com transparência critérios técnicos e considerando o impacto na equipe?',2,'No contexto do SAMU, tomar decisões técnicas (como seguir à risca os protocolos de triagem ou priorização de viaturas) e explicar os motivos de forma transparente para a equipe evita boatos na base e fortalece a confiança no comando.',true,'2026-06-30 13:32:48.121518','Liderado > Lider','c330d26c-8dcd-4311-ba2a-b3d1fa34c2eb'::uuid),
	 ('Técnico de Enfermagem','Comunicação e disponibilidade','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos?',2,'A líder monitora ativamente os atendimentos diários para garantir a qualidade assistencial. Realiza o planejamento e ajuste da tripulação (escala) de forma justa e eficiente. Executa o processo de acolhimento e treinamento prático de novos colaboradores (onboarding).',true,'2026-06-30 13:34:48.761055','Liderado > Lider','2bc6babc-960b-40fe-a6d5-4b831152db1e'::uuid),
	 ('Enfermeiro','Suporte e desenvolvimento','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU?',2,'Atuar na área de educação em urgências do SAMU, promover e facilitar atividades de educação permanente, desenvolver simulações realísticas e capacitações para a base.',true,'2026-06-30 16:28:45.057381','Liderado > Lider','4ca7918c-3881-477b-8873-e15c695dd622'::uuid),
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU?',2,'Atuar na área de educação em urgências do SAMU, promover e facilitar atividades de educação permanente, desenvolver simulações realísticas e capacitações para a base.',true,'2026-06-30 16:28:45.057381','Liderado > Lider','78940c86-68e2-4f51-bf75-c00e9ded129b'::uuid);
