	 ('Técnico de Enfermagem','Comunicação e disponibilidade','O líder está disponível e acessível quando a equipe precisa de suporte, orientação ou decisão rápida?',2,'onde os segundos salvam vidas e as crises operacionais acontecem a qualquer hora do dia ou da noite, ter um líder acessível para resolver impasses de frota, problemas na regulação ou conflitos na base é fundamental.',true,'2026-06-30 16:27:54.328435','Liderado > Lider','97fee518-3979-4806-80e1-7ea0cdba9a6a'::uuid),
	 ('Enfermeiro','Comunicação e disponibilidade','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',true,'2026-06-30 13:36:05.370723','Liderado > Lider','a99acf21-25c3-4085-b97b-b6cdfd66ae24'::uuid),
	 ('Médico','Comunicação e disponibilidade','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',true,'2026-06-30 13:36:05.370723','Liderado > Lider','58512567-74f9-4cc6-92fe-d6c8edd67f61'::uuid),
	 ('Técnico de Enfermagem','Comunicação e disponibilidade','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',true,'2026-06-30 13:36:05.370723','Liderado > Lider','6f457565-3aa8-4864-affb-ec4588a1392d'::uuid),
	 ('Condutor','Comportamental','Mantém controle emocional em cenários de alta tensão, múltiplas vítimas, violência ou óbito.',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','11665c7e-9d02-4f98-8f64-77eb8c27b271'::uuid),
	 ('Condutor','Processo e Qualidade','Contribui para o cumprimento do tempo-resposta ≤ 15 minutos da central ao local (parâmetro SAMU/Portaria 2.048).',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','4ce54254-14c6-4bd1-8ef0-f601bd3d5897'::uuid),
	 ('Condutor','Comportamental','Comunica-se de forma clara e objetiva com a equipe e com a Central de Regulação (CRUR-BF) durante o atendimento.',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','8c71e001-1df7-41f3-a777-6af9bd968872'::uuid),
	 ('Condutor','Técnico Operacional','Manuseia corretamente a maca, cadeira de rodas, prancha longa e colar cervical.',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','d75a410a-4b2b-4c5f-885f-5809539ea89e'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Condutor','Técnico Operacional','Pratica direção defensiva com habilidade, respeitando sinalização e garantindo a segurança da equipe e do paciente no deslocamento de emergência.',2,NULL,false,'2026-06-16 13:01:16.376169','Lider > Liderado','e6098065-d06e-438a-a637-b8ed0d63dedb'::uuid),
	 ('Enfermeiro','Liderança','Exerce liderança na USB/USA: dirige a equipe com clareza, distribui tarefas e coordena o atendimento.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','216e59f3-4ddc-4c83-8656-e74728907408'::uuid),
	 ('Médico','Comportamental','Demonstra responsabilidade e comprometimento, sendo referência de conduta profissional para toda a equipe.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','23b5a751-c34e-4b1a-98eb-a1c5a2a5f416'::uuid),
	 ('Médico','Técnico / Clínico','Conduz a PCR conforme ACLS: algoritmo, ritmo, medicação, tempo de RCP e ROSC — com taxa de retorno adequada.',2,NULL,false,'2026-06-16 14:33:45.376645','Lider > Liderado','fd196478-58c3-401a-a840-7b1dab2311aa'::uuid),
	 ('Condutor','Liderança e gestão','O colaborador entrega suas tarefas dentro do prazo estabelecido e com a qualidade técnica esperada para sua função',2,'Para enriquecer uma avaliação de desempenho ou um plano de desenvolvimento, é ideal adicionar exemplos práticos ou sugerir formas de elevar o nível atual de "esperado" para "excepcional',true,'2026-07-03 11:18:55.447965','Lider > Liderado','d1ace962-c3fc-4d17-9747-71aa67e95e2a'::uuid),
	 ('Condutor','Liderança e gestão','Demonstra domínio atualizado dos protocolos assistenciais e diretrizes do serviço?',2,'domínio atualizado sobre os protocolos assistenciais e diretrizes terapêuticas, incluindo as atualizações correntes estabelecidas pelo Ministério da Saúde e por sociedades de especialidade Diretrizes Públicas - SBOC.',true,'2026-07-03 11:18:55.447965','Lider > Liderado','b7426ec3-bdfa-4a33-8cc9-a415834ba480'::uuid),
	 ('Condutor','Liderança e gestão','Gerencia adequadamente o volume de demandas do plantão, mantendo organização e priorização correta das ocorrências?',2,'A gestão eficiente de um plantão depende da triagem contínua e da aplicação de metodologias ágeis de priorização para categorizar as ocorrências, garantindo que os casos mais críticos sejam resolvidos primeiro sem comprometer o fluxo geral de atendimento.',true,'2026-07-03 11:18:55.447965','Lider > Liderado','7fdaed31-3d38-468c-8f7a-eb7f51bbce70'::uuid),
	 ('Condutor','Comunicação e Disponibilidade','Comunica-se de forma clara, objetiva e empática com colegas de equipe e gestores, inclusive em situações de alta pressão?',2,'A comunicação clara, objetiva e empática é essencial para alinhar expectativas, resolver conflitos e manter um ambiente de trabalho colaborativo e saudável, inclusive sob alta pressão.',true,'2026-07-03 11:18:55.447965','Lider > Liderado','bbe0e3b1-58a0-450c-9b8a-9595127780d6'::uuid),
	 ('Condutor','Comunicação e Disponibilidade','Colabora ativamente com a equipe multiprofissional, respeitando as diferentes funções e contribuindo para a integração do cuidado?',2,'a colaboração ativa com a equipe multiprofissional, o respeito aos limites de atuação de cada especialidade e a comunicação clara são essenciais para um cuidado integral.',true,'2026-07-03 11:18:55.447965','Lider > Liderado','1c3bf99d-0fd5-49a9-a750-b2382bcd3c9b'::uuid),
	 ('Condutor','Comunicação e Disponibilidade','Mantém o equilíbrio emocional e o profissionalismo diante de situações adversas, críticas ou conflitos?',2,'Mantenho a serenidade, o foco na solução e uma postura ética, utilizando a escuta ativa e a comunicação empática para desarmar tensões.',true,'2026-07-03 11:18:55.447965','Lider > Liderado','666f656c-f187-4036-98ff-be13048a0e81'::uuid);
