	 ('Enfermeiro','Liderança','Usa comunicação em loop fechado (call-out, check-back) para garantir compreensão das ordens na cena',1,'Comunicação em loop (NTS)',false,'2026-06-11 15:06:08.472675','autoavaliacao','aa30d74b-35ac-4498-9dd9-332603117fb9'::uuid),
	 ('Enfermeiro','Técnico-Clínico','Executa técnica correta de movimentação e transporte de pacientes críticos sem agravar lesões',1,'Técnica de transporte',false,'2026-06-11 15:06:08.472675','autoavaliacao','766775ef-54df-4dc3-a161-59ea4a06c046'::uuid),
	 ('Enfermeiro','EIXO SOFT SKILLS','Participa ativamente do trabalho em equipe, recebe e transmite informações de forma padronizada (SBAR)?',1,'A comunicação SBAR é um método padronizado de transmissão de informações na área da saúde.',true,'2026-07-03 15:14:49.988354','autoavaliacao','cd5090a4-ffd6-4285-bb9b-02f7dff0cb1c'::uuid),
	 ('Enfermeiro','EIXO SOFT SKILLS','Mantém foco e equilíbrio emocional em situações de alta pressão (PCR, múltiplas vítimas, violência?)',1,'Em situações de alta pressão, manter a calma é vital. A regra de ouro é focar no próximo passo lógico—como checar vias aéreas na PCR ou triagem no trauma—e dominar respostas fisiológicas através do treinamento',true,'2026-07-03 15:14:49.988354','autoavaliacao','5ede0553-6a07-448c-b994-ae2022b00b17'::uuid),
	 ('Enfermeiro','EIXO SOFT SKILLS','Mantém consciência situacional: monitora o estado do paciente, equipamentos e ambiente simultaneamente?',1,'A consciência situacional na assistência ao paciente é a base da segurança e da eficácia clínica.',true,'2026-07-03 15:14:49.988354','autoavaliacao','a7804c47-2332-43f9-aeb7-d340ece689d8'::uuid),
	 ('Enfermeiro','EIXO SOFT SKILLS','Usa corretamente todos os EPIs e adota medidas de segurança para si, paciente e equipe em toda cena?',1,'O uso correto dos Equipamentos de Proteção Individual (EPIs) e a segurança da cena são os pilares do Atendimento Pré-Hospitalar (APH) e de emergências.',true,'2026-07-03 15:14:49.988354','autoavaliacao','ec03cbf4-ab92-4220-8266-4b69b5f66d3c'::uuid),
	 ('Enfermeiro','Metas e desenvolvimento - Transversais','Usa comunicação em loop fechado (call-out, check-back) para garantir compreensão das ordens na cena?',1,'Essa é a base da comunicação em circuito fechado (closed-loop communication), protocolo padrão-ouro de segurança.',true,'2026-07-03 15:14:49.988354','autoavaliacao','22b4d3f8-c2a6-49b1-a436-dab096365ca2'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Enfermeiro','Metas e desenvolvimento - Transversais','Exerce liderança na USB/USA: dirige a equipe com clareza, distribui tarefas e coordena o atendimento?',1,'A comunicação em circuito fechado (closed-loop communication) é uma técnica estruturada baseada em feedback. Ela evita ambiguidades e falhas humanas, sendo vital para ambientes de alta pressão',true,'2026-07-03 15:14:49.988354','autoavaliacao','d3bd49bb-47c4-413d-8965-8e3a99ed9336'::uuid),
	 ('Enfermeiro','EIXO PEOPLE SKILLS','Contribui para metas operacionais: tempo-resposta ≤15min, tempo de cena ≤20min, ROSC em PCR?',1,'Essas são metas operacionais críticas no Atendimento Pré-Hospitalar (APH).',true,'2026-07-03 15:14:49.988354','autoavaliacao','f095b371-16fb-4a57-bc3c-1e26d1ca3631'::uuid),
	 ('Enfermeiro','EIXO PEOPLE SKILLS','Registra o Processo de Enfermagem no SAMU de forma completa, legível e juridicamente válida?',1,'O registro do Processo de Enfermagem (PE) no SAMU deve ser completo, legível e juridicamente válido.',true,'2026-07-03 15:14:49.988354','autoavaliacao','3b719682-f25d-484c-ad7d-8e03ccec9487'::uuid),
	 ('Enfermeiro','EIXO TÉCNICO','Realiza avaliação primária (ABCDE) de forma rápida, sistemática e correta após chegada na cena?',1,'A avaliação primária é um método sistemático e rápido de triagem para identificar e tratar ameaças imediatas à vida.',true,'2026-07-03 15:14:49.988354','autoavaliacao','ced22b4d-243d-4730-981e-42ec2899fce1'::uuid),
	 ('Enfermeiro','EIXO TÉCNICO','Executa técnica correta de movimentação e transporte de pacientes críticos sem agravar lesões?',1,'A movimentação e o transporte seguros de pacientes críticos exigem planejamento sistematizado para evitar quedas, extubações acidentais, desconexão de drogas vasoativas e agravamento de lesões.',true,'2026-07-03 15:14:49.988354','autoavaliacao','4a820846-bb4d-41c2-8ff0-8ad6e1fdb5d7'::uuid),
	 ('Enfermeiro','EIXO TÉCNICO','Administra medicamentos de urgência com segurança, verificando via, dose, concentração e registro?',1,'administração segura de medicamentos de urgência exige a checagem rigorosa dos "13 Certos", focando especialmente na via (ex: EV, IM), dose, concentração (para evitar erros de diluição) e registro (que deve ser imediato)',true,'2026-07-03 15:14:49.988354','autoavaliacao','459c399f-45dd-45e9-a784-92c2c4467ed9'::uuid),
	 ('Enfermeiro','EIXO TÉCNICO','Executa corretamente compressões torácicas, ventilação (bolsa-valva-máscara) e desfibrilação com DEA conforme protocolo RCP e DEA?',1,'A Reanimação Cardiopulmonar (RCP) com uso de DEA e bolsa-valva-máscara (BVM) segue o protocolo de Suporte Básico de Vida (SBV). O objetivo é garantir a oxigenação cerebral e manter o fluxo sanguíneo.',true,'2026-07-03 15:14:49.988354','autoavaliacao','02996b6e-f228-4e51-a266-b72b9d81b9a0'::uuid),
	 ('Médico','EIXO PEOPLE SKILLS','Toma decisões rápidas e assertivas sob pressão extrema, com base em evidências e priorização correta?',1,'Tomar decisões rápidas e assertivas sob pressão exige um método estruturado para evitar a paralisia ou o pânico. O segredo é agir com base em dados concretos, filtrando o ruído e focando no que realmente importa para a resolução do problema.',false,'2026-07-03 15:24:48.674517','autoavaliacao','fa1d83f4-d31e-4873-8d64-9ac1317a4657'::uuid),
	 ('Médico','EIXO SOFT SKILLS','Aborda paciente e família com empatia, respeito, escuta ativa e informação adequada mesmo em cenários críticos?',1,'Abordar pacientes e famílias em cenários críticos exige humanização e técnica.',false,'2026-07-03 15:24:48.674517','autoavaliacao','ab407244-ec2f-4d03-a8aa-232dfd8df8a8'::uuid),
	 ('Médico','EIXO SOFT SKILLS','Comunica decisões de forma clara, utiliza comunicação em loop com a equipe e mantém registro verbal de ordens?',1,'Essas características descrevem um líder altamente organizado e focado em alta confiabilidade, prevenindo falhas de execução através de três pilares de excelência',false,'2026-07-03 15:24:48.674517','autoavaliacao','fa1dd3ff-a65a-4896-8697-5147be2edf66'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Médico','EIXO PEOPLE SKILLS','Mantém consciência situacional ampla (cena, paciente, equipe, recursos, tempo) e adapta o plano de cuidado?',1,'A consciência situacional é a capacidade dinâmica de observar, compreender e antecipar eventos',false,'2026-07-03 15:24:48.674517','autoavaliacao','6b6a8332-56b7-4f56-a168-c8561b62c056'::uuid),
	 ('Médico','EIXO SOFT SKILLS','Mantenho a calma e o tom de voz firme para estabilizar a equipe, o paciente e os familiares em momentos de desespero ou conflito?',1,'Demostrar habilidade essencial de liderança em ambientes de alta pressão, conhecida como comunicação de crise e gestão de agitação.',false,'2026-07-03 15:24:48.674517','autoavaliacao','07bc0e8e-876d-4c79-9760-fc9cbb6a9c4b'::uuid),
	 ('Médico','EIXO SOFT SKILLS','Lidera a equipe USA com autoridade, clareza e empatia: define papéis, distribui tarefas, mantém hierarquia e segurança?',1,'Liderar a equipe USA exige alinhar objetivos estratégicos com o desenvolvimento humano. Com autoridade para guiar, clareza na comunicação e empatia para apoiar, a gestão baseia-se em delegar responsabilidades, manter uma hierarquia de respeito mútuo e garantir um ambiente de trabalho seguro e focado em resultados',false,'2026-07-03 15:24:48.674517','autoavaliacao','3df18241-b2ae-48d5-8c5c-d38ee7c36a53'::uuid),
	 ('Médico','EIXO TÉCNICO','Comunica-se eficientemente com o médico regulador da CRUR-BF: informações precisas, decisão conjunta, tempo de regulação?',1,'A comunicação eficiente com o médico regulador da CRUR-BF (Central de Regulação de Urgências da Baixada Fluminense) baseia-se em três pilares: clareza e precisão dos dados clínicos, definição conjunta da conduta (acordo mútuo) e agilidade no tempo-resposta',false,'2026-07-03 15:24:48.674517','autoavaliacao','ac7e53cf-fda8-4454-90a1-f2d6d45188ef'::uuid),
	 ('Médico','EIXO TÉCNICO','Executa procedimentos de SAV com excelência: IOT difícil, acesso intraósseo, drenagem, cardioversão?',1,'A execução de excelência nos procedimentos de Suporte Avançado de Vida (SAV) exige domínio técnico, raciocínio rápido e seguimento estrito dos algoritmos.',false,'2026-07-03 15:24:48.674517','autoavaliacao','3228fd6b-d52b-4c52-aab9-6fcacb8836de'::uuid),
	 ('Médico','EIXO TÉCNICO','Conduz a PCR conforme ACLS: algoritmo, ritmo, medicação, tempo de RCP, ROSC — taxa de retorno adequada?',1,'A condução de uma Parada Cardiorrespiratória (PCR) no Suporte Avançado de Vida em Cardiologia (ACLS) baseia-se na RCP de alta qualidade',false,'2026-07-03 15:24:48.674517','autoavaliacao','ef98144f-59d7-4285-844e-420bca5c5877'::uuid),
	 ('Médico','EIXO TÉCNICO','Realiza avaliação clínica completa e rápida, formulando diagnóstico sindromático correto no pré-hospitalar?',1,'No atendimento pré-hospitalar (APH), a avaliação clínica baseia-se em protocolos padronizados de resposta rápida.',false,'2026-07-03 15:24:48.674517','autoavaliacao','9fe0148c-5284-4afe-ab81-43ea31ac7318'::uuid),
	 ('Médico','Metas e desenvolvimento - Transversais','Sou receptivo(a) a feedbacks construtivos da equipe após uma ocorrência.? É excelente ter essa abertura?',1,'Profissionais que acolhem feedbacks construtivos após incidentes transformam falhas em oportunidades de aprendizado e fortalecem a confiança e colaboração em toda a equipe.',false,'2026-07-03 15:24:48.674517','autoavaliacao','6f6d6d98-de03-4a87-bb20-c9afd141b369'::uuid),
	 ('Médico','Metas e desenvolvimento - Transversais','Utilizo comunicação em loop fechado (call-out e check-back) de forma consistente nos atendimentos.?',1,'A comunicação em loop fechado (alça fechada) é um dos pilares da Comunicação Efetiva, essencial para cumprir as metas internacionais de segurança do paciente, prevenir falhas e garantir que condutas críticas sejam executadas',false,'2026-07-03 15:24:48.674517','autoavaliacao','ee94efaa-586a-4697-b423-47ea8e0af253'::uuid),
	 ('Médico','EIXO SOFT SKILLS','Aborda paciente e família com empatia, respeito, escuta ativa e informação adequada mesmo em cenários críticos?',1,'Abordar pacientes e famílias em cenários críticos exige humanização e técnica.',true,'2026-07-03 15:25:26.733','autoavaliacao','dd7061b1-e2fc-4aca-9ae9-81697b494398'::uuid);
